**Cooldown System Example**
```javascript
class Cooldown {
  constructor(duration) {
    this.duration = duration;
    this.lastActivated = 0;
  }

  isReady() {
    const currentTime = Date.now();
    return currentTime - this.lastActivated >= this.duration;
  }

  activate() {
    this.lastActivated = Date.now();
  }
}

// Example usage:
const cooldown = new Cooldown(10000); // 10 second cooldown
console.log(cooldown.isReady()); // false
cooldown.activate();
console.log(cooldown.isReady()); // true
setTimeout(() => {
  console.log(cooldown.isReady()); // false
}, 10001);
```

